command:
mkdir -p .claude-tdd-pro/space space && printf '{"id":"m1","dimension":"performance"}
' > .claude-tdd-pro/space/collected.jsonl && printf 'dimensions: {performance: {enabled: true}}
retention_days: 90
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/space-export.sh" --collected .claude-tdd-pro/space/collected.jsonl --out export.json --config space/config.yaml 2>err.txt && grep -q '"share":"never"' export.json && grep -q '"included_dimensions":\["performance"\]' export.json && grep -q '"retention_days":90' export.json && echo ok 1>&2
